## Tests

Create `apps/client/src/layers/entities/pulse/__tests__/use-pulse-preset-dialog.test.ts`:

```typescript
import { describe, it, expect, beforeEach } from 'vitest';
import { act, renderHook } from '@testing-library/react';
import { usePulsePresetDialog } from '../model/use-pulse-preset-dialog';
import type { PulsePreset } from '@dorkos/shared/types';

const MOCK_PRESET: PulsePreset = {
  id: 'health-check',
  name: 'Health Check',
  description: 'Run lint, tests, and type-check to catch issues early.',
  prompt: 'Run the project health checks: lint, test, and typecheck.',
  cron: '0 8 * * 1',
  timezone: 'UTC',
  category: 'maintenance',
};

describe('usePulsePresetDialog', () => {
  beforeEach(() => {
    // Reset Zustand store between tests
    act(() => { usePulsePresetDialog.setState({ pendingPreset: null, externalTrigger: false }); });
  });

  it('initialises with null pendingPreset and externalTrigger=false', () => {
    const { result } = renderHook(() => usePulsePresetDialog());
    expect(result.current.pendingPreset).toBeNull();
    expect(result.current.externalTrigger).toBe(false);
  });

  it('openWithPreset sets pendingPreset and externalTrigger=true', () => {
    const { result } = renderHook(() => usePulsePresetDialog());
    act(() => { result.current.openWithPreset(MOCK_PRESET); });
    expect(result.current.pendingPreset).toEqual(MOCK_PRESET);
    expect(result.current.externalTrigger).toBe(true);
  });

  it('clear resets pendingPreset to null and externalTrigger to false', () => {
    const { result } = renderHook(() => usePulsePresetDialog());
    act(() => { result.current.openWithPreset(MOCK_PRESET); });
    act(() => { result.current.clear(); });
    expect(result.current.pendingPreset).toBeNull();
    expect(result.current.externalTrigger).toBe(false);
  });

  it('calling openWithPreset twice overwrites the previous preset', () => {
    const OTHER: PulsePreset = { ...MOCK_PRESET, id: 'docs-sync', name: 'Docs Sync' };
    const { result } = renderHook(() => usePulsePresetDialog());
    act(() => { result.current.openWithPreset(MOCK_PRESET); });
    act(() => { result.current.openWithPreset(OTHER); });
    expect(result.current.pendingPreset?.id).toBe('docs-sync');
  });
});
```

## Overview

Move `PresetCard` from `features/onboarding/ui/PresetCard.tsx` to `features/pulse/ui/PresetCard.tsx`. Add a `selectable` variant to the existing `toggle` variant so the card can be used in the dialog picker, the empty state, and the sidebar.

## Step 1 — Create features/pulse/ui/PresetCard.tsx

Create `apps/client/src/layers/features/pulse/ui/PresetCard.tsx`:

```typescript
import { Switch } from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import type { PulsePreset } from '@/layers/entities/pulse';
import { formatCron } from './format-cron';
import { useSpotlight } from './use-spotlight';

interface PresetCardProps {
  /** The preset to display */
  preset: PulsePreset;
  /** Interaction variant: toggle switch (onboarding) or click-to-select (dialog/gallery) */
  variant: 'toggle' | 'selectable';
  /** For variant='toggle': controlled checked state */
  checked?: boolean;
  /** For variant='toggle': called on toggle change */
  onCheckedChange?: (checked: boolean) => void;
  /** For variant='selectable': called when card is clicked */
  onSelect?: (preset: PulsePreset) => void;
  /** For variant='selectable': whether this card is currently selected */
  selected?: boolean;
  /** Additional class names */
  className?: string;
}

/**
 * Card displaying a Pulse schedule preset.
 *
 * Two variants:
 * - `toggle`: shows a Switch control, used in onboarding.
 * - `selectable`: click-to-select with a selection ring, used in dialog picker and empty states.
 *
 * Features a mouse-tracking spotlight effect on hover.
 *
 * @param preset - The preset data to display
 * @param variant - Controls which interaction style is rendered
 * @param checked - For toggle variant: controlled checked state
 * @param onCheckedChange - For toggle variant: called on toggle change
 * @param onSelect - For selectable variant: called when card is clicked
 * @param selected - For selectable variant: whether this card is currently selected
 */
export function PresetCard({
  preset,
  variant,
  checked,
  onCheckedChange,
  onSelect,
  selected = false,
  className,
}: PresetCardProps) {
  const { onMouseMove, onMouseLeave, spotlightStyle } = useSpotlight();

  const handleClick = () => {
    if (variant === 'toggle') {
      onCheckedChange?.(!checked);
    } else {
      onSelect?.(preset);
    }
  };

  return (
    <button
      type="button"
      onClick={handleClick}
      onMouseMove={onMouseMove}
      onMouseLeave={onMouseLeave}
      className={cn(
        'relative flex w-full items-start gap-4 rounded-lg border p-4 text-left transition',
        'hover:bg-accent/50',
        'min-h-11',
        variant === 'toggle' && checked && 'border-primary/40 bg-accent/30',
        variant === 'selectable' && selected && 'border-primary ring-1 ring-primary bg-accent/30',
        className
      )}
    >
      {/* Spotlight overlay */}
      {spotlightStyle && (
        <div
          className="pointer-events-none absolute inset-0 rounded-lg"
          style={spotlightStyle}
        />
      )}

      {/* Toggle switch — only for toggle variant */}
      {variant === 'toggle' && (
        <div className="flex size-11 shrink-0 items-center justify-center">
          <Switch
            checked={checked ?? false}
            onCheckedChange={onCheckedChange}
            aria-label={`Enable ${preset.name}`}
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      )}

      <div className="min-w-0 flex-1 space-y-1">
        <div className="font-medium">{preset.name}</div>
        <p className="text-sm text-muted-foreground">{preset.description}</p>
        <p className="text-xs text-muted-foreground">{formatCron(preset.cron)}</p>
        <p className="line-clamp-2 text-sm text-muted-foreground/80">{preset.prompt}</p>
      </div>
    </button>
  );
}
```

## Step 2 — Copy lib files

The `PresetCard` uses two utilities currently at `features/onboarding/lib/`:
- `format-cron.ts`
- `use-spotlight.ts`

These must be moved/copied to `features/pulse/ui/` (or to `features/pulse/lib/` if that directory exists). Check if `apps/client/src/layers/features/pulse/` has a `lib/` directory — if not, create `apps/client/src/layers/features/pulse/lib/`. Copy both files there and update the imports in `PresetCard.tsx` to use the new paths.

If `onboarding` has other components that still use `format-cron.ts` or `use-spotlight.ts`, keep the originals in `features/onboarding/lib/` too (do not delete them yet).

## Step 3 — Update features/onboarding PresetCard shim

Replace the content of `apps/client/src/layers/features/onboarding/ui/PresetCard.tsx` with a re-export shim:

```typescript
// Deprecated: use PresetCard from features/pulse instead.
