import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, screen, fireEvent, cleanup } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import type { ReactNode } from 'react';
import type { PulsePreset } from '@dorkos/shared/types';
import { PresetGallery } from '../ui/PresetGallery';

const PRESETS: PulsePreset[] = [
  { id: 'health-check', name: 'Health Check', description: 'Lint and test', prompt: 'Run checks', cron: '0 8 * * 1', timezone: 'UTC', category: 'maintenance' },
  { id: 'docs-sync', name: 'Docs Sync', description: 'Sync docs', prompt: 'Review docs', cron: '0 10 * * *', timezone: 'UTC', category: 'documentation' },
];

// Mock usePulsePresets at the entities/pulse barrel
