  it('shows error message on error', () => {
    mockUsePulsePresets.mockReturnValue({ isLoading: false, isError: true, data: undefined });
    render(<PresetGallery />, { wrapper: Wrapper });
    expect(screen.getByText(/Failed to load presets/i)).toBeTruthy();
  });

  it('renders a card for each preset', () => {
    mockUsePulsePresets.mockReturnValue({ isLoading: false, isError: false, data: PRESETS });
    render(<PresetGallery />, { wrapper: Wrapper });
    expect(screen.getByTestId('card-health-check')).toBeTruthy();
    expect(screen.getByTestId('card-docs-sync')).toBeTruthy();
  });

  it('calls onSelect with the correct preset when a card is clicked', () => {
    mockUsePulsePresets.mockReturnValue({ isLoading: false, isError: false, data: PRESETS });
    const onSelect = vi.fn();
    render(<PresetGallery onSelect={onSelect} />, { wrapper: Wrapper });
    fireEvent.click(screen.getByTestId('card-health-check'));
    expect(onSelect).toHaveBeenCalledWith(PRESETS[0]);
  });

  it('passes selected=true to the card matching selectedId', () => {
    mockUsePulsePresets.mockReturnValue({ isLoading: false, isError: false, data: PRESETS });
    render(<PresetGallery selectedId="docs-sync" />, { wrapper: Wrapper });
    expect(screen.getByTestId('card-docs-sync').getAttribute('data-selected')).toBe('true');
    expect(screen.getByTestId('card-health-check').getAttribute('data-selected')).toBe('false');
  });

  it('handles empty preset list gracefully', () => {
    mockUsePulsePresets.mockReturnValue({ isLoading: false, isError: false, data: [] });
    render(<PresetGallery />, { wrapper: Wrapper });
    expect(screen.getByText(/No presets available/i)).toBeTruthy();
  });
});
```

## Overview

Modify `CreateScheduleDialog` to introduce a two-step flow: step 1 is a preset picker (shows `PresetGallery`), step 2 is the existing form with an optional back button. The dialog also reacts to external triggers from `usePulsePresetDialog` (e.g., from the sidebar) to open directly at step 2 with a preset pre-populated.

## Current state

The file is at `apps/client/src/layers/features/pulse/ui/CreateScheduleDialog.tsx`. It currently renders a single-step form. The `buildInitialState` function already handles creating initial form state from an `editSchedule`.

## Step 1 — Add step and appliedPreset state

Add these state declarations near the top of `CreateScheduleDialog` (after existing state lines):

```typescript
type DialogStep = 'preset-picker' | 'form';
const [step, setStep] = useState<DialogStep>(() =>
  editSchedule ? 'form' : 'preset-picker'
);
const [appliedPreset, setAppliedPreset] = useState<PulsePreset | null>(null);
```

Update the existing `useEffect` that resets form on dialog open/close to also reset the step:

```typescript
useEffect(() => {
  setForm(buildInitialState(editSchedule));
  setAppliedPreset(null);
  if (!editSchedule) {
    setScheduleTarget('agent');
    setStep('preset-picker'); // Reset to picker when dialog closes and reopens
  } else {
    setScheduleTarget(editSchedule.agentId ? 'agent' : (editSchedule.cwd ? 'directory' : 'agent'));
    setStep('form'); // Edit mode always starts at form
  }
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, [editSchedule, open]);
```

## Step 2 — Wire external trigger from usePulsePresetDialog

Add import at the top:
```typescript
import { usePulsePresetDialog } from '@/layers/entities/pulse';
import type { PulsePreset } from '@/layers/entities/pulse';
```

Add the following inside the component body (after existing hook calls):

```typescript
const { pendingPreset, externalTrigger, clear } = usePulsePresetDialog();

// When SchedulesView (or any other feature) fires openWithPreset(),
// jump directly to the form step with that preset pre-populated.
useEffect(() => {
  if (externalTrigger && pendingPreset) {
    setAppliedPreset(pendingPreset);
    setForm(buildInitialState(undefined, pendingPreset));
    setStep('form');
    clear();
