    setAppliedPreset(initialPreset);
    setStep('form');
  } else {
    setForm(buildInitialState());
    setStep('preset-picker');
  }
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, [editSchedule, open, initialPreset]);
